class Solution:
    def minSwaps(self, s: str) -> int:
        open_needed = 0
        for ch in s:
            if ch == '[':
                open_needed += 1
            else:
                if open_needed > 0:
                    open_needed -= 1
        return (open_needed + 1) // 2
```
